mapper.select:
SELECT id, bank_id, type, content, options, answer, analysis, difficulty, knowledge_point, score, create_by, create_time, update_by, update_time, is_deleted FROM edu_exam_question WHERE is_deleted = 0 AND bank_id = #{bankId}
AND type = #{type}
AND difficulty = #{difficulty}
AND knowledge_point LIKE CONCAT('%', #{knowledgePoint}, '%')
ORDER BY create_time DESC LIMIT #{limit}
